settings.customCss:
@import url('https://fonts.googleapis.com/css2?family=Inter:wght@300;400;500;600;700&display=swap');

/* ===== Scope root: CSS variables (theme_selector overrides these) ===== */
.mf-contact-split {
  --background: oklch(0.98 0.002 240);
  --foreground: oklch(0.20 0.04 240);
  --card: oklch(1 0 0);
  --card-foreground: oklch(0.20 0.04 240);
  --primary: oklch(0.35 0.12 240);
  --primary-foreground: oklch(0.98 0 0);
  --secondary: oklch(0.94 0.01 240);
  --muted: oklch(0.96 0.005 240);
  --muted-foreground: oklch(0.45 0.02 240);
  --accent: oklch(0.55 0.08 240);
  --border: oklch(0.90 0.01 240);
  --input: oklch(0.97 0.005 240);
  --ring: oklch(0.35 0.12 240);

  display: block !important;
  width: 100% !important;
  min-height: 100%;
  position: relative;
  background: var(--background);
  color: var(--foreground);
  font-family: 'Inter', system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif !important;
  box-sizing: border-box;
  overflow: hidden !important;
}
.mf-contact-split *,
.mf-contact-split *::before,
.mf-contact-split *::after {
  box-sizing: border-box;
}
.mf-contact-split * {
  font-family: 'Inter', system-ui, -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif !important;
}

/* ===== Background ===== */
.mf-contact-split .mf-bg {
  position: absolute;
  inset: 0;
  background: var(--background);
  z-index: 0;
  pointer-events: none;
}
.mf-contact-split .mf-overlay {
  position: absolute;
  inset: 0;
  background: linear-gradient(135deg, color-mix(in oklab, var(--primary) 4%, transparent) 0%, transparent 60%);
  z-index: 0;
  pointer-events: none;
}

/* ===== Content wrapper ===== */
.mf-contact-split .mf-content {
  position: relative;
  z-index: 1;
  width: 100%;
  padding: 24px 16px;
}
@media (min-width: 768px) {
  .mf-contact-split .mf-content {
    padding: 40px 24px;
  }
}
@media (min-width: 1024px) {
  .mf-contact-split .mf-content {
    padding: 56px 32px;
  }
}

/* ===== Split grid: map beside form ===== */
.mf-contact-split .mf-split-grid {
  display: grid;
  grid-template-columns: 1fr;
  gap: 24px;
  max-width: 1200px;
  margin: 0 auto;
  align-items: stretch;
}
@media (min-width: 992px) {
  .mf-contact-split .mf-split-grid {
    grid-template-columns: 1fr 1fr;
    gap: 32px;
  }
}
@media (min-width: 1200px) {
  .mf-contact-split .mf-split-grid {
    grid-template-columns: 5fr 7fr;
    gap: 40px;
  }
}

/* Map on the left visually */
.mf-contact-split.mf-map-left .mf-map-col {
  order: 0;
}
.mf-contact-split.mf-map-left .mf-form-col {
  order: 1;
}
/* Map on the right visually */
.mf-contact-split.mf-map-right .mf-map-col {
  order: 1;
}
.mf-contact-split.mf-map-right .mf-form-col {
  order: 0;
}
/* Mobile: form always first, map second for better UX */
@media (max-width: 991px) {
  .mf-contact-split .mf-form-col { order: 0 !important; }
  .mf-contact-split .mf-map-col { order: 1 !important; }
}

/* ===== Map column ===== */
.mf-contact-split .mf-map-col {
  display: flex;
  flex-direction: column;
  gap: 20px;
}
.mf-contact-split .mf-map-wrap {
  flex: 1 1 auto;
  min-height: 360px;
  border-radius: 12px;
  overflow: hidden;
  border: 1px solid var(--border);
  box-shadow: 0 10px 25px -5px rgba(0,0,0,.08);
}
.mf-contact-split .mf-map-iframe {
  width: 100%;
  height: 100%;
  min-height: 360px;
  border: 0;
  display: block;
}
@media (min-width: 992px) {
  .mf-contact-split .mf-map-wrap,
  .mf-contact-split .mf-map-iframe {
    min-height: 480px;
  }
}

/* ===== Contact info under map ===== */
.mf-contact-split .mf-contact-info {
  background: var(--card);
  border: 1px solid var(--border);
  border-radius: 12px;
  padding: 20px;
  box-shadow: 0 4px 12px rgba(0,0,0,.04);
}
.mf-contact-split .mf-contact-title {
  margin: 0 0 12px;
  font-size: 1.125rem;
  font-weight: 600;
  color: var(--foreground);
}
.mf-contact-split .mf-contact-line {
  margin: 0 0 8px;
  font-size: 0.9375rem;
  line-height: 1.6;
  color: var(--muted-foreground);
}
.mf-contact-split .mf-contact-address {
  white-space: pre-line;
}

/* ===== Form card ===== */
.mf-contact-split .mf-card {
  background: var(--card) !important;
  border: 1px solid var(--border) !important;
  border-radius: 16px !important;
  box-shadow: 0 20px 40px -10px rgba(0,0,0,.1) !important;
  overflow: hidden;
  height: 100%;
  display: flex;
  flex-direction: column;
}
.mf-contact-split .mf-header {
  padding: 28px 28px 20px;
  border-bottom: 1px solid var(--border);
}
.mf-contact-split .mf-title {
  margin: 0 0 8px;
  font-size: clamp(1.75rem, 4vw, 2.5rem);
  font-weight: 600;
  line-height: 1.15;
  color: var(--foreground);
}
.mf-contact-split .mf-lead {
  margin: 0;
  font-size: 1rem;
  line-height: 1.6;
  color: var(--muted-foreground);
}
.mf-contact-split .mf-section {
  padding: 24px 28px;
  flex: 1 1 auto;
}
.mf-contact-split .mf-section-label {
  margin: 0 0 18px;
  font-size: 0.75rem;
  font-weight: 600;
  letter-spacing: 0.12em;
  text-transform: uppercase;
  color: var(--muted-foreground);
}

/* ===== Fields grid ===== */
.mf-contact-split .mf-fields {
  display: flex;
  flex-direction: column;
  gap: 16px;
}
.mf-contact-split .mf-row {
  width: 100%;
}
.mf-contact-split .mf-grid-2 {
  display: grid;
  grid-template-columns: 1fr;
  gap: 16px;
}
@media (min-width: 576px) {
  .mf-contact-split .mf-grid-2 {
    grid-template-columns: 1fr 1fr;
  }
}

/* ===== Inputs (override host styles) ===== */
.mf-contact-split input[type="text"],
.mf-contact-split input[type="email"],
.mf-contact-split input[type="tel"],
.mf-contact-split select,
.mf-contact-split textarea {
  width: 100% !important;
  padding: 12px 14px !important;
  font-size: 0.9375rem !important;
  line-height: 1.5 !important;
  color: var(--foreground) !important;
  background: var(--input) !important;
  border: 1px solid var(--border) !important;
  border-radius: 8px !important;
  outline: none !important;
  transition: border-color .15s, box-shadow .15s !important;
}
.mf-contact-split input:focus,
.mf-contact-split select:focus,
.mf-contact-split textarea:focus {
  border-color: var(--primary) !important;
  box-shadow: 0 0 0 3px color-mix(in oklab, var(--primary) 18%, transparent) !important;
}
.mf-contact-split label {
  display: block;
  margin-bottom: 6px;
  font-size: 0.875rem;
  font-weight: 500;
  color: var(--foreground);
}
.mf-contact-split .mf-required label::after {
  content: " *";
  color: var(--accent);
}

/* ===== Submit ===== */
.mf-contact-split .mf-submit-wrap {
  padding: 0 28px 24px;
}
.mf-contact-split .mf-submit-wrap button,
.mf-contact-split .mf-submit-wrap input[type="submit"] {
  width: 100%;
  padding: 14px 24px !important;
  font-size: 1rem !important;
  font-weight: 600 !important;
  color: var(--primary-foreground) !important;
  background: var(--primary) !important;
  border: 1px solid var(--primary) !important;
  border-radius: 10px !important;
  cursor: pointer;
  transition: filter .15s, transform .15s !important;
}
.mf-contact-split .mf-submit-wrap button:hover,
.mf-contact-split .mf-submit-wrap input[type="submit"]:hover {
  filter: brightness(1.08);
  transform: translateY(-1px);
}

/* ===== Footer ===== */
.mf-contact-split .mf-footer {
  padding: 16px 28px 24px;
  border-top: 1px solid var(--border);
  text-align: center;
}
.mf-contact-split .mf-footer p {
  margin: 0;
  font-size: 0.875rem;
  color: var(--muted-foreground);
}

/* ===== Hide theme preset UI interference ===== */
.mf-contact-split .mf-theme-ui {
  position: fixed;
  z-index: 9999;
}


/* ===== ISSUE 2 FIX: integrate outer band + wire preset channel ===== */
/* (a) Neutralise the gray outer band so the map + form-card sit directly on the
   page like the mock (transparent by default). A picked MegaForm preset
   recolours the page via --mf-preset-bg; with no preset it stays transparent. */
.mf-contact-split {
  background: var(--mf-preset-bg, transparent) !important;
  border: 0 !important;
}
.mf-contact-split .mf-bg {
  background: var(--mf-preset-bg, transparent) !important;
}
.mf-contact-split .mf-overlay {
  background: transparent !important;
}
/* drop the oversized empty top/bottom padding band; keep side gutters for mobile */
.mf-contact-split .mf-content {
  padding-top: 0 !important;
  padding-bottom: 0 !important;
}
/* (b) Wire the inner white card + contact-info surface to the preset channel.
   No preset -> falls back to var(--card) = original oklch(1 0 0) white (byte-identical).
   Corporate's original .mf-contact-info background IS var(--card), so this is identity-safe here. */
.mf-contact-split .mf-card,
.mf-contact-split .mf-contact-info {
  background: var(--mf-preset-surface, var(--card)) !important;
}

/* MF-QA-CMAP-OPTIONS-v20 — radio/checkbox card styling ported from map-left-minimal
   (same .mf-contact-split scope + shadcn vars, so corporate palette applies automatically) */
.mf-contact-split .mf-option-group {
  display: grid !important;
  grid-template-columns: minmax(0, 1fr) !important;
  gap: 8px !important;
  margin: 0 !important;
  padding: 0 !important;
}
.mf-contact-split .mf-field-group[data-type="Radio"] .mf-option-group {
  grid-template-columns: repeat(2, minmax(0, 1fr)) !important;
}
.mf-contact-split .mf-option-item,
.mf-contact-split label.mf-option-item {
  display: flex !important;
  align-items: center !important;
  gap: 9px !important;
  min-height: 42px !important;
  width: 100% !important;
  margin: 0 !important;
  padding: 9px 11px !important;
  cursor: pointer;
  color: var(--foreground) !important;
  background: color-mix(in oklab, var(--muted) 72%, var(--card) 28%) !important;
  border: 1px solid var(--border) !important;
  border-radius: 6px !important;
}
.mf-contact-split .mf-option-item input[type="radio"],
.mf-contact-split .mf-option-item input[type="checkbox"] {
  flex: 0 0 auto !important;
  width: 16px !important;
  height: 16px !important;
  min-height: 16px !important;
  margin: 0 !important;
  padding: 0 !important;
  accent-color: var(--primary);
}
.mf-contact-split .mf-option-label {
  display: block !important;
  min-width: 0;
  color: var(--foreground) !important;
  font-size: .88rem !important;
  font-weight: 550 !important;
  line-height: 1.25 !important;
}
.mf-contact-split .mf-row,
  .mf-contact-split .mf-field-group,
  .mf-contact-split input[type="text"],
  .mf-contact-split input[type="email"],
  .mf-contact-split input[type="tel"],
  .mf-contact-split select,
  .mf-contact-split textarea,
  .mf-contact-split .mf-input,
  .mf-contact-split .mf-select,
  .mf-contact-split .mf-textarea,
  .mf-contact-split .mf-option-group,
  .mf-contact-split .mf-option-item {
    max-width: 100% !important;
  }
.mf-contact-split .mf-title,
  .mf-contact-split .mf-lead,
  .mf-contact-split .mf-section-label,
  .mf-contact-split .mf-field-label,
  .mf-contact-split .mf-option-label,
  .mf-contact-split .mf-footer p,
